import socket
import threading
import json
import time
import math
import random

class Player:
    def __init__(self, client_socket, address, player_id):
        self.socket = client_socket
        self.address = address
        self.id = player_id
        self.x = random.uniform(0, 1000)
        self.y = random.uniform(0, 1000)
        self.z = 0
        self.health = 100
        self.alive = True
        self.username = f"Player_{player_id}"
        self.rotation = 0
        self.velocity_x = 0
        self.velocity_y = 0
        self.last_update = time.time()

class GameServer:
    def __init__(self, host='0.0.0.0', port=9999):
        self.host = host
        self.port = port
        self.server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.server_socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self.players = {}
        self.player_id_counter = 0
        self.running = False
        self.lock = threading.Lock()
        self.game_state = {
            'players': {},
            'safe_zone': {'x': 500, 'y': 500, 'radius': 500},
            'timestamp': time.time()
        }

    def start(self):
        self.server_socket.bind((self.host, self.port))
        self.server_socket.listen(100)
        self.running = True
        print(f"Battle Royale Server started on {self.host}:{self.port}")
        
        threading.Thread(target=self.accept_connections, daemon=True).start()
        threading.Thread(target=self.broadcast_game_state, daemon=True).start()
        threading.Thread(target=self.update_game_logic, daemon=True).start()

    def accept_connections(self):
        while self.running:
            try:
                client_socket, address = self.server_socket.accept()
                with self.lock:
                    player_id = self.player_id_counter
                    self.player_id_counter += 1
                    player = Player(client_socket, address, player_id)
                    self.players[player_id] = player
                
                print(f"Player {player_id} connected from {address}")
                
                welcome_msg = {
                    'type': 'welcome',
                    'player_id': player_id,
                    'x': player.x,
                    'y': player.y
                }
                self.send_to_client(client_socket, welcome_msg)
                
                threading.Thread(target=self.handle_client, args=(player,), daemon=True).start()
            except Exception as e:
                if self.running:
                    print(f"Error accepting connection: {e}")

    def handle_client(self, player):
        buffer = ""
        try:
            while self.running and player.alive:
                data = player.socket.recv(4096).decode('utf-8')
                if not data:
                    break
                
                buffer += data
                while '\n' in buffer:
                    line, buffer = buffer.split('\n', 1)
                    if line:
                        try:
                            message = json.loads(line)
                            self.process_client_message(player, message)
                        except json.JSONDecodeError:
                            pass
        except Exception as e:
            print(f"Error handling client {player.id}: {e}")
        finally:
            self.disconnect_player(player)

    def process_client_message(self, player, message):
        msg_type = message.get('type')
        
        if msg_type == 'update_position':
            with self.lock:
                player.x = message.get('x', player.x)
                player.y = message.get('y', player.y)
                player.z = message.get('z', player.z)
                player.rotation = message.get('rotation', player.rotation)
                player.velocity_x = message.get('velocity_x', 0)
                player.velocity_y = message.get('velocity_y', 0)
                player.last_update = time.time()
        
        elif msg_type == 'shoot':
            target_id = message.get('target_id')
            if target_id in self.players:
                with self.lock:
                    target = self.players[target_id]
                    target.health -= message.get('damage', 10)
                    if target.health <= 0:
                        target.alive = False
                        target.health = 0

    def update_game_logic(self):
        while self.running:
            time.sleep(0.1)
            
            with self.lock:
                current_time = time.time()
                
                for player in list(self.players.values()):
                    if player.alive:
                        distance_from_center = math.sqrt(
                            (player.x - self.game_state['safe_zone']['x']) ** 2 +
                            (player.y - self.game_state['safe_zone']['y']) ** 2
                        )
                        
                        if distance_from_center > self.game_state['safe_zone']['radius']:
                            player.health -= 1
                            if player.health <= 0:
                                player.alive = False
                                player.health = 0

    def broadcast_game_state(self):
        while self.running:
            time.sleep(0.05)
            
            with self.lock:
                self.game_state['timestamp'] = time.time()
                self.game_state['players'] = {}
                
                for player_id, player in self.players.items():
                    self.game_state['players'][player_id] = {
                        'id': player.id,
                        'username': player.username,
                        'x': player.x,
                        'y': player.y,
                        'z': player.z,
                        'rotation': player.rotation,
                        'velocity_x': player.velocity_x,
                        'velocity_y': player.velocity_y,
                        'health': player.health,
                        'alive': player.alive
                    }
                
                state_message = {
                    'type': 'game_state',
                    'state': self.game_state
                }
                
                disconnected = []
                for player_id, player in self.players.items():
                    try:
                        self.send_to_client(player.socket, state_message)
                    except:
                        disconnected.append(player_id)
                
                for player_id in disconnected:
                    if player_id in self.players:
                        self.disconnect_player(self.players[player_id])

    def send_to_client(self, client_socket, message):
        try:
            data = json.dumps(message) + '\n'
            client_socket.sendall(data.encode('utf-8'))
        except Exception as e:
            raise e

    def disconnect_player(self, player):
        with self.lock:
            if player.id in self.players:
                print(f"Player {player.id} disconnected")
                del self.players[player.id]
        try:
            player.socket.close()
        except:
            pass

    def stop(self):
        self.running = False
        with self.lock:
            for player in list(self.players.values()):
                try:
                    player.socket.close()
                except:
                    pass
            self.players.clear()
        self.server_socket.close()


class GameClient:
    def __init__(self, host='127.0.0.1', port=9999):
        self.host = host
        self.port = port
        self.socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.running = False
        self.player_id = None
        self.game_state = {}
        self.x = 0
        self.y = 0
        self.render_distance = 300
        self.lock = threading.Lock()

    def connect(self):
        self.socket.connect((self.host, self.port))
        self.running = True
        print(f"Connected to server at {self.host}:{self.port}")
        
        threading.Thread(target=self.receive_messages, daemon=True).start()

    def receive_messages(self):
        buffer = ""
        try:
            while self.running:
                data = self.socket.recv(8192).decode('utf-8')
                if not data:
                    break
                
                buffer += data
                while '\n' in buffer:
                    line, buffer = buffer.split('\n', 1)
                    if line:
                        try:
                            message = json.loads(line)
                            self.process_message(message)
                        except json.JSONDecodeError:
                            pass
        except Exception as e:
            print(f"Error receiving messages: {e}")
        finally:
            self.running = False

    def process_message(self, message):
        msg_type = message.get('type')
        
        if msg_type == 'welcome':
            self.player_id = message.get('player_id')
            self.x = message.get('x')
            self.y = message.get('y')
            print(f"Assigned player ID: {self.player_id}")
            print(f"Starting position: ({self.x}, {self.y})")
        
        elif msg_type == 'game_state':
            with self.lock:
                self.game_state = message.get('state', {})

    def send_position_update(self, x, y, z=0, rotation=0, velocity_x=0, velocity_y=0):
        self.x = x
        self.y = y
        message = {
            'type': 'update_position',
            'x': x,
            'y': y,
            'z': z,
            'rotation': rotation,
            'velocity_x': velocity_x,
            'velocity_y': velocity_y
        }
        self.send_message(message)

    def send_shoot(self, target_id, damage=10):
        message = {
            'type': 'shoot',
            'target_id': target_id,
            'damage': damage
        }
        self.send_message(message)

    def send_message(self, message):
        try:
            data = json.dumps(message) + '\n'
            self.socket.sendall(data.encode('utf-8'))
        except Exception as e:
            print(f"Error sending message: {e}")

    def get_visible_players(self):
        visible_players = []
        with self.lock:
            players = self.game_state.get('players', {})
            for player_id, player_data in players.items():
                if player_id == self.player_id:
                    continue
                
                distance = math.sqrt(
                    (player_data['x'] - self.x) ** 2 +
                    (player_data['y'] - self.y) ** 2
                )
                
                if distance <= self.render_distance and player_data['alive']:
                    visible_players.append({
                        'id': player_id,
                        'data': player_data,
                        'distance': distance
                    })
        
        return visible_players

    def render_game(self):
        visible_players = self.get_visible_players()
        print(f"\n--- Game State (Player {self.player_id}) ---")
        print(f"Position: ({self.x:.1f}, {self.y:.1f})")
        print(f"Visible players: {len(visible_players)}")
        
        for player_info in visible_players:
            player_data = player_info['data']
            distance = player_info['distance']
            print(f"  Player {player_info['id']}: "
                  f"Pos({player_data['x']:.1f}, {player_data['y']:.1f}) "
                  f"Health: {player_data['health']} "
                  f"Distance: {distance:.1f}")

    def disconnect(self):
        self.running = False
        try:
            self.socket.close()
        except:
            pass


if __name__ == "__main__":
    import sys
    
    if len(sys.argv) > 1 and sys.argv[1] == "server":
        server = GameServer()
        server.start()
        
        try:
            while True:
                time.sleep(1)
        except KeyboardInterrupt:
            print("\nShutting down server...")
            server.stop()
    
    else:
        client = GameClient()
        client.connect()
        
        time.sleep(1)
        
        try:
            for i in range(10):
                new_x = client.x + random.uniform(-10, 10)
                new_y = client.y + random.uniform(-10, 10)
                client.send_position_update(new_x, new_y)
                
                time.sleep(0.5)
                client.render_game()
                
        except KeyboardInterrupt:
            print("\nDisconnecting...")
        finally:
            client.disconnect()